fun solve(n: Long, edges: Array<Array<Long>>, label: String): Long {
    val adj = Array(n.toInt()) { mutableListOf<Long>() }
    for (i in edges.indices) {
        val u = edges[i][0]
        val v = edges[i][1]
        adj[u.toInt()].add(v.toInt())
        adj[v.toInt()].add(u.toInt())
    }

    var result = 0L

    fun isPalindrome(s: String): Boolean {
        return s == s.reversed()
    }

    fun dfs(node: Long, path: MutableList<Long>, visited: BooleanArray) {
        val s = path.map { label[it.toInt()] }.joinToString("")
        if (isPalindrome(s)) {
            result = Math.max(result, s.length.toLong())
        }

        for (neighbor in adj[node.toInt()]) {
            if (!visited[neighbor.toInt()]) {
                visited[neighbor.toInt()] = true
                path.add(neighbor)
                dfs(neighbor, path, visited)
                path.removeLast()
                visited[neighbor.toInt()] = false
            }
        }
    }

    val visited = BooleanArray(n.toInt())
    for (i in 0 until n) {
        visited[i] = true
        val path = mutableListOf<Long>().apply { add(i.toLong()) }
        dfs(i.toLong(), path, visited)
        visited[i] = false
    }

    return result
}
